# portfolio_monitor.py
# Weekly portfolio health check

from collections import defaultdict
import json

# Simulated request log (replace with actual telemetry pull)
request_log = [
    {"provider": "anthropic", "task_type": "summarization", "input_tokens": 800, "output_tokens": 350, "cost_usd": 0.0075},
    {"provider": "anthropic", "task_type": "classification", "input_tokens": 200, "output_tokens": 50, "cost_usd": 0.0011},
    {"provider": "self-hosted", "task_type": "classification", "input_tokens": 200, "output_tokens": 50, "cost_usd": 0.00004},
    # ... thousands of records
]

def portfolio_health(logs: list[dict]) -> dict:
    by_provider = defaultdict(lambda: {"count": 0, "cost": 0.0})
    for r in logs:
        by_provider[r["provider"]]["count"] += 1
        by_provider[r["provider"]]["cost"] += r.get("cost_usd", 0)

    total_cost = sum(v["cost"] for v in by_provider.values())
    return {
        provider: {
            "request_share": data["count"] / len(logs),
            "spend_share": data["cost"] / total_cost if total_cost > 0 else 0,
        }
        for provider, data in by_provider.items()
    }

PORTFOLIO_TARGETS = {
    "anthropic":   {"spend_share": (0.55, 0.75)},   # 60–70% ± tolerance
    "self-hosted": {"spend_share": (0.10, 0.30)},   # 15–25% ± tolerance
    "openai":      {"spend_share": (0.05, 0.20)},   # 10–15% ± tolerance
}

health = portfolio_health(request_log)
print("Portfolio allocation vs targets:")
for provider, stats in health.items():
    spend = stats["spend_share"]
    target = PORTFOLIO_TARGETS.get(provider, {}).get("spend_share", (0, 1))
    status = "OK" if target[0] <= spend <= target[1] else "DRIFT"
    print(f"  {provider:15s}  spend: {spend:.1%}  target: {target[0]:.0%}–{target[1]:.0%}  [{status}]")
